SELECT COUNT(1)
FROM app_human_chat_conversation
WHERE user_id = #{userId}
  AND peer_user_id = #{peerUserId}
  AND status = 'normal'

SELECT COUNT(1)
FROM app_social_friend
WHERE user_id = #{userId}
  AND friend_user_id = #{peerUserId}
  AND status = 'normal'
  AND deleted_at IS NULL

SELECT *
FROM app_human_chat_message
WHERE from_user_id = #{fromUserId}
  AND client_msg_id = #{clientMsgId}
LIMIT 1

SELECT
FROM app_human_chat_message m LEFT JOIN app_user from_user ON from_user.id = m.from_user_id LEFT JOIN app_h5_user_profile_ext from_ext ON from_ext.user_id = m.from_user_id LEFT JOIN app_user to_user ON to_user.id = m.to_user_id LEFT JOIN app_h5_user_profile_ext to_ext ON to_ext.user_id = m.to_user_id WHERE m.conversation_key = #{conversationKey} AND (m.from_user_id = #{viewerId} OR m.to_user_id = #{viewerId})
AND m.id < #{beforeMessageId}
ORDER BY m.id DESC LIMIT #{limit}

