UPDATE app_human_chat_message
SET is_read = 1,
    read_at = COALESCE(read_at, CURRENT_TIMESTAMP),
    updated_at = CURRENT_TIMESTAMP
WHERE conversation_key = #{conversationKey}
  AND to_user_id = #{readerUserId}
  AND from_user_id = #{peerUserId}
  AND is_read = 0
  AND status = 'normal'

UPDATE app_human_chat_conversation
SET unread_count = 0,
    updated_at = CURRENT_TIMESTAMP
WHERE user_id = #{userId}
  AND peer_user_id = #{peerUserId}

