SELECT
FROM app_human_chat_message m LEFT JOIN app_user from_user ON from_user.id = m.from_user_id LEFT JOIN app_h5_user_profile_ext from_ext ON from_ext.user_id = m.from_user_id LEFT JOIN app_user to_user ON to_user.id = m.to_user_id LEFT JOIN app_h5_user_profile_ext to_ext ON to_ext.user_id = m.to_user_id
